package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private CSVRecord csvRecord;
    private String[] values;
    private Map<String, Integer> mapping;

    @BeforeEach
    void setUp() {
        values = new String[] {"value1", "value2", "value3"};
        mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);
    }

    @Test
    void testIsConsistent_mappingNull() throws Exception {
        // Create CSVRecord with mapping = null
        csvRecord = createCSVRecord(values, null, "comment", 1L);

        // isConsistent should return true when mapping is null
        assertTrue(invokeIsConsistent(csvRecord));
    }

    @Test
    void testIsConsistent_mappingSizeEqualsValuesLength() throws Exception {
        // mapping size equals values length
        csvRecord = createCSVRecord(values, mapping, "comment", 1L);

        // isConsistent should return true
        assertTrue(invokeIsConsistent(csvRecord));
    }

    @Test
    void testIsConsistent_mappingSizeNotEqualsValuesLength() throws Exception {
        // mapping size not equal to values length
        Map<String, Integer> smallerMapping = new HashMap<>();
        smallerMapping.put("col1", 0);
        smallerMapping.put("col2", 1);
        // values length = 3, mapping size = 2

        csvRecord = createCSVRecord(values, smallerMapping, "comment", 1L);

        // isConsistent should return false
        assertFalse(invokeIsConsistent(csvRecord));
    }

    private CSVRecord createCSVRecord(String[] values, Map<String, Integer> mapping, String comment, long recordNumber) throws Exception {
        // Use reflection to invoke package-private constructor
        return new CSVRecord(values, mapping, comment, recordNumber);
    }

    private boolean invokeIsConsistent(CSVRecord record) throws Exception {
        // isConsistent is public so can call directly
        return record.isConsistent();
    }
}
